-- Fetch the first 4 records from the fact_transactions table
SELECT * FROM sigma_analytics.fact_transactions LIMIT 4;

-- Calculate revenue from completed transactions
SELECT SUM(amount) AS revenue FROM sigma_analytics.fact_transactions WHERE status = 'COMPLETED';

-- Calculate failure rate
SELECT (COUNT(CASE WHEN status = 'FAILED' THEN 1 END) / COUNT(*)) * 100 AS failure_rate FROM sigma_analytics.fact_transactions;
